import { useNavigate } from "react-router-dom";
// 1. Import your image correctly
import thereseImg from "../images/therese.png";
import "./index.css";

function AboutMe() {
  const navigate = useNavigate();

  return (
    <div className="homepage-container">
      <div className="content-wrapper">
        <h2 className="h2-homepage">Hi, I'm Therese</h2>

        <div className="two-column-layout">
          <div className="left-panel">
            {/* 2. Use the imported variable name */}
            <img
              src={thereseImg}
              alt="Therese Wong"
              style={{ width: "100%", borderRadius: "12px" }}
            />
          </div>
          <div className="right-panel">
            {/* <h2 className="h2-homepage">About Me</h2> */}
            <p>
              I'm a candidate for a Bachelor of Science in Interactive Arts &
              Technology and a Business Certification in Innovation &
              Entrepreneurship. Currently, I work as a Service Desk Technician
              for SFU IT Services.
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}

export default AboutMe;
